      sourceUrl: text("source_url"),
      // Page URL where the lead was captured
      conversationId: varchar("conversation_id").references(() => conversations.id, { onDelete: "set null" }),
      topicsOfInterest: jsonb("topics_of_interest").$type(),
      // AI-extracted topics from conversation (3-4 labels)
      // LeadSquared CRM sync tracking
      leadsquaredSyncStatus: text("leadsquared_sync_status"),
      // null | 'pending' | 'synced' | 'failed'
