    aiSuggestions = pgTable("ai_suggestions", {
      id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
      businessAccountId: varchar("business_account_id").notNull().references(() => businessAccounts.id, { onDelete: "cascade" }),
      // Suggestion details
      type: text("type").notNull(),
      // 'faq', 'training', 'journey', 'product', 'personality'
      title: text("title").notNull(),
      description: text("description").notNull(),
      suggestedContent: jsonb("suggested_content"),
      // The actual FAQ/instruction/journey template/etc
      // Supporting data
      conversationCount: numeric("conversation_count", { precision: 10, scale: 0 }).default("0"),
      // How many conversations led to this
      confidence: numeric("confidence", { precision: 5, scale: 2 }).default("0"),
      // AI confidence 0-100
      priority: text("priority").default("medium"),
      // 'high', 'medium', 'low'
      // Supporting evidence
      exampleQuestions: jsonb("example_questions"),
      // Array of example questions that led to this suggestion
      conversationIds: jsonb("conversation_ids"),
      // Array of conversation IDs that support this
      // Status
      status: text("status").notNull().default("pending"),
      // 'pending', 'accepted', 'dismissed'
      acceptedAt: timestamp("accepted_at"),
      acceptedBy: varchar("accepted_by").references(() => users.id, { onDelete: "set null" }),
      dismissedAt: timestamp("dismissed_at"),
      dismissedBy: varchar("dismissed_by").references(() => users.id, { onDelete: "set null" }),
      dismissReason: text("dismiss_reason"),
      // Impact tracking (populated after acceptance)
      impactMetrics: jsonb("impact_metrics"),
      // { questionsReduced: 10, satisfactionIncrease: 5, etc }
      implementedId: varchar("implemented_id"),
      // ID of created FAQ/training/etc
      createdAt: timestamp("created_at").notNull().defaultNow(),
      updatedAt: timestamp("updated_at").notNull().defaultNow()
    });
