    urgencyOfferSettings = pgTable("urgency_offer_settings", {
      id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
      businessAccountId: varchar("business_account_id").notNull().references(() => businessAccounts.id, { onDelete: "cascade" }),
      name: text("name").notNull().default("Default Campaign"),
      priority: integer("priority").notNull().default(0),
      isEnabled: boolean("is_enabled").notNull().default(false),
      countdownDurationMinutes: integer("countdown_duration_minutes").notNull().default(10),
      discountType: text("discount_type").notNull().default("percentage"),
      discountValue: integer("discount_value").notNull().default(10),
      headline: text("headline").notNull().default("Limited Time Offer!"),
      description: text("description").notNull().default("We noticed you're interested! Here's a special discount just for you."),
      ctaButtonText: text("cta_button_text").notNull().default("Unlock Offer"),
      dismissButtonText: text("dismiss_button_text").notNull().default("Maybe later"),
      successMessage: text("success_message").notNull().default("Your discount code has been sent to your WhatsApp!"),
      phoneInputLabel: text("phone_input_label").notNull().default("Enter your WhatsApp number"),
      phoneInputPlaceholder: text("phone_input_placeholder").notNull().default("+1 234 567 8900"),
      requirePhone: boolean("require_phone").notNull().default(true),
      triggerMode: text("trigger_mode").notNull().default("intent"),
      triggerKeywords: text("trigger_keywords").default(""),
      intentThreshold: integer("intent_threshold").notNull().default(70),
      minMessagesBeforeTrigger: integer("min_messages_before_trigger").notNull().default(3),
      maxOffersPerVisitor: integer("max_offers_per_visitor").notNull().default(1),
      cooldownMinutes: integer("cooldown_minutes").notNull().default(30),
      showReminderAfterDismiss: boolean("show_reminder_after_dismiss").notNull().default(true),
      createdAt: timestamp("created_at").notNull().defaultNow(),
      updatedAt: timestamp("updated_at").notNull().defaultNow()
    });
    urgencyOffers = pgTable("urgency_offers", {
      id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
      businessAccountId: varchar("business_account_id").notNull().references(() => businessAccounts.id, { onDelete: "cascade" }),
      campaignId: varchar("campaign_id").references(() => urgencyOfferSettings.id, { onDelete: "set null" }),
      visitorToken: text("visitor_token").notNull(),
      conversationId: varchar("conversation_id").references(() => conversations.id, { onDelete: "set null" }),
      // Timer tracking (for persistence across refreshes)
      countdownStartedAt: timestamp("countdown_started_at").notNull().defaultNow(),
      countdownExpiresAt: timestamp("countdown_expires_at").notNull(),
      // Offer details (captured from settings at time of offer)
      discountType: text("discount_type").notNull(),
      discountValue: integer("discount_value").notNull(),
      discountCode: text("discount_code").notNull(),
      // Generated unique code
      // Phone redemption (WhatsApp-first)
      phoneNumber: text("phone_number"),
      // Captured when user redeems offer
      phoneCountryCode: text("phone_country_code"),
      // Country code for formatting
      // Status tracking
      status: text("status").notNull().default("active"),
      // 'active' | 'redeemed' | 'expired' | 'dismissed'
      dismissedAt: timestamp("dismissed_at"),
      redeemedAt: timestamp("redeemed_at"),
      expiredAt: timestamp("expired_at"),
      // AI intent data at time of trigger
      intentScore: numeric("intent_score", { precision: 5, scale: 2 }),
      triggerMessage: text("trigger_message"),
      // The message that triggered high intent detection
      createdAt: timestamp("created_at").notNull().defaultNow()
    }, (table) => [
      index("urgency_offers_visitor_idx").on(table.businessAccountId, table.visitorToken),
      index("urgency_offers_phone_idx").on(table.businessAccountId, table.phoneNumber),
      index("urgency_offers_status_idx").on(table.businessAccountId, table.status)
    ]);
    erpConfigurations = pgTable("erp_configurations", {
      id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
      businessAccountId: varchar("business_account_id").notNull().unique().references(() => businessAccounts.id, { onDelete: "cascade" }),
      // ERP connection details
      name: text("name").notNull(),
      // Display name for this ERP connection
      erpType: text("erp_type").notNull().default("generic"),
      // 'generic' | 'sap' | 'oracle' | 'microsoft_dynamics' | 'custom'
      baseUrl: text("base_url").notNull(),
      // ERP API base URL
      // Authentication (encrypted)
      authType: text("auth_type").notNull().default("api_key"),
      // 'api_key' | 'bearer_token' | 'oauth2' | 'basic'
      apiKey: text("api_key"),
      // Encrypted API key
      accessToken: text("access_token"),
      // Encrypted access token
      refreshToken: text("refresh_token"),
      // Encrypted refresh token (for OAuth2)
      tokenExpiresAt: timestamp("token_expires_at"),
      // When access token expires
      basicAuthUsername: text("basic_auth_username"),
      // For basic auth
      basicAuthPassword: text("basic_auth_password"),
      // Encrypted password for basic auth
      // API endpoints configuration
      productsEndpoint: text("products_endpoint").default("/products"),
      // Endpoint for product listing
      productDetailEndpoint: text("product_detail_endpoint").default("/products/{id}"),
      // Endpoint for single product
      categoriesEndpoint: text("categories_endpoint").default("/categories"),
      // Endpoint for categories
      deltaSyncEndpoint: text("delta_sync_endpoint"),
      // Endpoint for delta sync (products updated since timestamp)
      // Sync configuration
      syncEnabled: text("sync_enabled").notNull().default("true"),
      // 'true' | 'false'
      syncFrequencyHours: integer("sync_frequency_hours").notNull().default(12),
      // How often to sync (hours)
      fullSyncDayOfWeek: integer("full_sync_day_of_week").default(0),
      // 0=Sunday, 6=Saturday - day for full sync
      batchSize: integer("batch_size").notNull().default(500),
      // Products per batch during sync
      // Field mapping (JSON) - maps ERP fields to our standard fields
      fieldMapping: jsonb("field_mapping"),
      // { "erp_product_id": "id", "erp_name": "name", "erp_price": "price", ... }
      // Caching configuration
      cacheEnabled: text("cache_enabled").notNull().default("true"),
      // 'true' | 'false'
      cacheTtlMinutes: integer("cache_ttl_minutes").notNull().default(30),
      // Cache TTL in minutes
      // Status
      isActive: text("is_active").notNull().default("true"),
      // 'true' | 'false'
      lastTestedAt: timestamp("last_tested_at"),
      // Last connection test
      lastTestStatus: text("last_test_status"),
      // 'success' | 'failed'
      lastTestError: text("last_test_error"),
      // Error message from last test
      createdAt: timestamp("created_at").notNull().defaultNow(),
      updatedAt: timestamp("updated_at").notNull().defaultNow()
    });
    productEmbeddings = pgTable("product_embeddings", {
      id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
      businessAccountId: varchar("business_account_id").notNull().references(() => businessAccounts.id, { onDelete: "cascade" }),
      // ERP product reference
      erpProductId: text("erp_product_id").notNull(),
      // Product ID from client's ERP
      erpConfigurationId: varchar("erp_configuration_id").references(() => erpConfigurations.id, { onDelete: "cascade" }),
      // Image information (not stored, just reference)
      imageUrl: text("image_url").notNull(),
      // Original image URL from ERP
      imageHash: text("image_hash"),
      // Hash of image for change detection
      // Embedding data
      embedding: vector768("embedding"),
      // Vector embedding for visual similarity search using Jina CLIP (768 dimensions)
      visualDescription: text("visual_description"),
      // AI-generated visual description
      // Cached product metadata (for quick display without ERP call)
      cachedName: text("cached_name"),
      // Product name at time of sync
      cachedCategory: text("cached_category"),
      // Product category at time of sync
      cachedPrice: numeric("cached_price", { precision: 10, scale: 2 }),
      // Product price at time of sync
      cachedThumbnailUrl: text("cached_thumbnail_url"),
      // Thumbnail URL for quick display
      // Sync metadata
      lastSyncedAt: timestamp("last_synced_at").notNull().defaultNow(),
      syncVersion: integer("sync_version").notNull().default(1),
      // Incremented on each sync
      isActive: text("is_active").notNull().default("true"),
      // 'true' | 'false' - soft delete
      createdAt: timestamp("created_at").notNull().defaultNow(),
      updatedAt: timestamp("updated_at").notNull().defaultNow()
    }, (table) => ({
      // Index for fast lookup by business + ERP product ID
      uniqueBusinessErpProduct: uniqueIndex("product_embeddings_business_erp_idx").on(table.businessAccountId, table.erpProductId)
      // Note: Vector embedding index should be created with HNSW (not btree) via raw SQL for similarity search
    }));
    erpSyncLogs = pgTable("erp_sync_logs", {
      id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
      businessAccountId: varchar("business_account_id").notNull().references(() => businessAccounts.id, { onDelete: "cascade" }),
      erpConfigurationId: varchar("erp_configuration_id").references(() => erpConfigurations.id, { onDelete: "cascade" }),
      // Sync details
      syncType: text("sync_type").notNull(),
      // 'full' | 'delta' | 'manual'
      status: text("status").notNull().default("running"),
      // 'running' | 'completed' | 'failed' | 'cancelled'
      // Progress tracking
      totalProducts: integer("total_products").default(0),
      // Total products to process
      processedProducts: integer("processed_products").default(0),
      // Products processed so far
      newEmbeddings: integer("new_embeddings").default(0),
      // New embeddings created
      updatedEmbeddings: integer("updated_embeddings").default(0),
      // Existing embeddings updated
      deletedEmbeddings: integer("deleted_embeddings").default(0),
      // Embeddings removed (product no longer in ERP)
      failedProducts: integer("failed_products").default(0),
      // Products that failed to process
      // Resumable sync support
      lastProcessedPage: integer("last_processed_page").default(0),
      // For resuming interrupted syncs
      lastProcessedProductId: text("last_processed_product_id"),
      // Last product ID processed
      useBatchApi: text("use_batch_api").default("false"),
      // 'true' | 'false' - Whether to use OpenAI Batch API
      embeddingMethod: text("embedding_method").default("standard"),
      // 'standard' | 'batch' - Embedding generation method
      // Timing
      startedAt: timestamp("started_at").notNull().defaultNow(),
      completedAt: timestamp("completed_at"),
      durationSeconds: integer("duration_seconds"),
      // Error tracking
      errorMessage: text("error_message"),
      errorDetails: jsonb("error_details"),
      // Detailed error information
      createdAt: timestamp("created_at").notNull().defaultNow()
    });
    erpProductCache = pgTable("erp_product_cache", {
      id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
      businessAccountId: varchar("business_account_id").notNull().references(() => businessAccounts.id, { onDelete: "cascade" }),
      erpConfigurationId: varchar("erp_configuration_id").references(() => erpConfigurations.id, { onDelete: "cascade" }),
      // ERP product reference
      erpProductId: text("erp_product_id").notNull(),
      // Cached product data
      name: text("name").notNull(),
      description: text("description"),
      sku: text("sku"),
      price: numeric("price", { precision: 10, scale: 2 }),
      currency: text("currency").default("INR"),
      category: text("category"),
      subcategory: text("subcategory"),
      images: jsonb("images"),
      // Array of image URLs
      inStock: text("in_stock").default("true"),
      // 'true' | 'false'
      weight: text("weight"),
      metal: text("metal"),
      additionalAttributes: jsonb("additional_attributes"),
      // Any extra fields from ERP
      // Cache metadata
      cachedAt: timestamp("cached_at").notNull().defaultNow(),
      expiresAt: timestamp("expires_at"),
      // When cache expires
      isValid: text("is_valid").notNull().default("true"),
      // 'true' | 'false' - invalidated on ERP update
      createdAt: timestamp("created_at").notNull().defaultNow(),
      updatedAt: timestamp("updated_at").notNull().defaultNow()
    }, (table) => ({
      // Unique constraint for business + ERP product ID
      uniqueBusinessErpProductCache: uniqueIndex("erp_product_cache_business_erp_idx").on(table.businessAccountId, table.erpProductId),
      // Index for category filtering
      categoryIdx: index("erp_product_cache_category_idx").on(table.businessAccountId, table.category),
      // Index for price filtering
      priceIdx: index("erp_product_cache_price_idx").on(table.businessAccountId, table.price)
    }));
    productImportJobs = pgTable("product_import_jobs", {
      id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
      businessAccountId: varchar("business_account_id").notNull().references(() => businessAccounts.id, { onDelete: "cascade" }),
      // Job status
      status: text("status").notNull().default("pending"),
      // 'pending' | 'processing' | 'completed' | 'failed' | 'cancelled'
      // Progress tracking
      totalRows: integer("total_rows").notNull().default(0),
      processedRows: integer("processed_rows").notNull().default(0),
      successCount: integer("success_count").notNull().default(0),
      errorCount: integer("error_count").notNull().default(0),
      // Embedding progress
      totalEmbeddings: integer("total_embeddings").notNull().default(0),
      processedEmbeddings: integer("processed_embeddings").notNull().default(0),
      // File info
      fileName: text("file_name"),
      fileSize: integer("file_size"),
      // Error tracking
      errors: jsonb("errors"),
      // Array of error messages with row info
      // Timing
      startedAt: timestamp("started_at"),
      completedAt: timestamp("completed_at"),
      createdAt: timestamp("created_at").notNull().defaultNow(),
      updatedAt: timestamp("updated_at").notNull().defaultNow()
    }, (table) => ({
      businessIdIdx: index("product_import_jobs_business_idx").on(table.businessAccountId),
      statusIdx: index("product_import_jobs_status_idx").on(table.status)
    }));
    openAiBatchJobs = pgTable("openai_batch_jobs", {
      id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
      businessAccountId: varchar("business_account_id").notNull().references(() => businessAccounts.id, { onDelete: "cascade" }),
      // Link to sync log (for ERP sync) or import job (for Excel import)
      erpSyncLogId: varchar("erp_sync_log_id").references(() => erpSyncLogs.id, { onDelete: "cascade" }),
      productImportJobId: varchar("product_import_job_id").references(() => productImportJobs.id, { onDelete: "cascade" }),
      // OpenAI Batch API IDs
      openAiBatchId: text("openai_batch_id"),
      // The batch ID from OpenAI API
      openAiInputFileId: text("openai_input_file_id"),
      // Input file ID
      openAiOutputFileId: text("openai_output_file_id"),
      // Output file ID (after completion)
      // Job details
      jobType: text("job_type").notNull().default("embedding"),
      // 'embedding' | 'visual_description'
      status: text("status").notNull().default("pending"),
      // 'pending' | 'uploading' | 'submitted' | 'in_progress' | 'completed' | 'failed' | 'expired' | 'cancelled'
      // Progress tracking
      totalRequests: integer("total_requests").notNull().default(0),
      completedRequests: integer("completed_requests").notNull().default(0),
      failedRequests: integer("failed_requests").notNull().default(0),
      // Batch file data (stored temporarily for creating batch)
      batchInputData: jsonb("batch_input_data"),
      // Array of product IDs and image URLs for batch processing
      // Results
      results: jsonb("results"),
      // Processed results after batch completion
      // Error tracking
      errorMessage: text("error_message"),
      errorDetails: jsonb("error_details"),
      // Timing
      submittedAt: timestamp("submitted_at"),
      completedAt: timestamp("completed_at"),
      expiresAt: timestamp("expires_at"),
      // OpenAI batch expiration (24 hours)
      createdAt: timestamp("created_at").notNull().defaultNow(),
      updatedAt: timestamp("updated_at").notNull().defaultNow()
    }, (table) => ({
      businessIdIdx: index("openai_batch_jobs_business_idx").on(table.businessAccountId),
      statusIdx: index("openai_batch_jobs_status_idx").on(table.status),
      batchIdIdx: index("openai_batch_jobs_batch_id_idx").on(table.openAiBatchId)
    }));
