      status: text("status").notNull().default("new"),
      // 'new' | 'processing' | 'completed' | 'rejected' | 'message_only'
      direction: text("direction").notNull().default("incoming"),
      // 'incoming' | 'outgoing' - message direction
      flowSessionId: varchar("flow_session_id"),
      // Links message to a WhatsApp flow session for journey grouping
      leadsquaredLeadId: text("leadsquared_lead_id"),
      // LeadSquared lead ID if synced
      leadsquaredSyncStatus: text("leadsquared_sync_status"),
      // null | 'pending' | 'synced' | 'failed'
