      customCrmSyncError: text("custom_crm_sync_error"),
      customCrmSyncPayload: jsonb("custom_crm_sync_payload"),
      customCrmSyncedAt: timestamp("custom_crm_synced_at"),
      lastMessageAt: timestamp("last_message_at"),
      // When the most recent message was received (for sorting by activity)
      lastMessage: text("last_message"),
      // Text of the most recent message
      conversationCount: integer("conversation_count").notNull().default(1),
      // Number of messages/interactions on this lead
      receivedAt: timestamp("received_at").notNull().defaultNow(),
      // When message was received
      createdAt: timestamp("created_at").notNull().defaultNow(),
      updatedAt: timestamp("updated_at").notNull().defaultNow()
