      async getTicketStats(businessAccountId) {
        const tickets = await db.select().from(supportTickets).where(eq4(supportTickets.businessAccountId, businessAccountId));
        const stats = {
          total: tickets.length,
          open: tickets.filter((t) => t.status === "open").length,
          inProgress: tickets.filter((t) => t.status === "in_progress").length,
          resolved: tickets.filter((t) => t.status === "resolved").length,
          closed: tickets.filter((t) => t.status === "closed").length,
          autoResolved: tickets.filter((t) => t.autoResolved === "true").length,
          avgResolutionTime: 0
        };
        const resolvedTickets = tickets.filter((t) => t.resolvedAt);
        if (resolvedTickets.length > 0) {
          const totalTime = resolvedTickets.reduce((sum, ticket) => {
            const created = new Date(ticket.createdAt).getTime();
            const resolved = new Date(ticket.resolvedAt).getTime();
            return sum + (resolved - created);
          }, 0);
          stats.avgResolutionTime = Math.round(totalTime / resolvedTickets.length / (1e3 * 60 * 60));
        }
        return stats;
      }
