  app2.get("/api/public/proactive-guidance-match/:businessAccountId", async (req, res) => {
    try {
      const { businessAccountId } = req.params;
      const { url } = req.query;
      if (!businessAccountId) {
        return res.status(400).json({ error: "Business account ID is required" });
      }
      if (!url || typeof url !== "string") {
        return res.status(400).json({ error: "URL is required" });
      }
      const rules = await storage.getActiveProactiveGuidanceRules(businessAccountId);
      let matchingRule = null;
      for (const rule of rules) {
        const pattern = rule.urlPattern;
        let isMatch = false;
        if (pattern === url) {
          isMatch = true;
        }
        if (!isMatch && pattern.includes("*")) {
          const escaped = pattern.replace(/[.+?^${}()|[\]\\]/g, "\\$&");
          const regexPattern = escaped.replace(/\*/g, ".*");
          const regex = new RegExp("^" + regexPattern + "$");
          if (regex.test(url)) {
            isMatch = true;
          }
        }
        if (!isMatch && url.startsWith(pattern)) {
          isMatch = true;
        }
        if (isMatch) {
          matchingRule = rule;
          break;
        }
      }
      res.json(matchingRule);
    } catch (error) {
      console.error("[Proactive Guidance] Error matching rule:", error);
      res.status(500).json({ error: error.message });
    }
  });
